<template>
  <v-container fluid fill-height align-start ma-0 pa-2>
    <v-row no-gutters>
      <i-page-title title="menuOfgroupManage" />
      <v-col cols="12" sm="12" lg="12" class="pa-2 pb-0">
        <i-card-top class="d-md-flex" :useBtnList="buttonUseList" @btnSearch="btnSearch()" @btnSave="btnSave()">
          <!-- headerTitle="권한그룹" -->
          <template v-slot:body>
            <v-layout column>
              <v-row no-gutters align="center" class="pa-0 pt-2">
                <v-col cols="12" md="2">
                  <v-text-field
                    class="search-text-field mx-1"
                    placeholder="통합 검색"
                    dense
                    outlined
                    hide-details="auto"
                    @change="changeInput"
                    clearable
                  />
                </v-col>

                <v-col cols="12" md="2">
                  <v-select
                    :menu-props="{ offsetY: true }"
                    class="search-select mx-1 pt-2 py-md-0"
                    placeholder="권한그룹"
                    dense
                    outlined
                    clearable
                    :items="selectList"
                    item-text="grpAuthNm"
                    item-value="grpAuthCd"
                    v-model="selectedGrpAuth"
                  />
                </v-col>
                <!-- <v-select class="pa-2 search-select" label="권한유무"
                      :prepend-icon="'$search'" :items="authDataSource" 
                      item-text="minorNm" item-value="minorCd"
                      v-model="selectedAuth" /> -->
                <v-col cols="12" md="8" class="pl-md-3 d-md-flex d-block pt-1 pt-md-0">
                  <v-radio-group v-model="selectedAuth" row>
                    <v-radio
                      color="radio"
                      v-for="(item, index) in authDataSource"
                      :key="index"
                      :label="item.minorNm"
                      v-model="item.minorCd"
                    ></v-radio>
                  </v-radio-group>
                  <v-radio-group v-model="selectedSvcGubn" row>
                    <v-radio
                      color="radio"
                      v-for="(item, index) in svcGubnDataSource"
                      :key="index"
                      :label="item.minorNm"
                      v-model="item.minorCd"
                    ></v-radio>
                  </v-radio-group>
                </v-col>
              </v-row>
            </v-layout>
          </template>
        </i-card-top>
      </v-col>
      <v-col cols="12" sm="12" lg="12" class="pa-2 pt-0">
        <i-card-vertical headerTitle="그룹메뉴 관리" device="web">
          <template v-slot:body>
            <v-layout column>
              <v-col cols="12" md="12" class="row pa-0">
                <v-col cols="12" md="12" sm="12" class="pa-0">
                  <DxTreeList
                    id="menuOfgroupManageTreeList"
                    class="layout-col-height00"
                    width="100%"
                    :ref="dxTreeListRef"
                    :data-source="menus"
                    :auto-expand-all="true"
                    :hover-state-enabled="true"
                    :show-row-lines="true"
                    :column-hiding-enabled="false"
                    :show-borders="true"
                    :column-auto-width="true"
                    :allow-column-resizing="false"
                    :root-value="0"
                    :focused-row-enabled="true"
                    data-structure="plain"
                    key-expr="id"
                    parent-id-expr="parentId"
                    @selection-changed="onSelectionChanged"
                    @editing-start="onEditingStart"
                    @editor-preparing="onEditorPreparing"
                  >
                    <!-- 선택모드  -->
                    <DxSelection mode="multiple" :recursive="true" />
                    <!-- mode : "multiple" | "none" -->
                    <!-- 수정 -->
                    <DxEditing :allow-updating="true" mode="batch" :select-text-on-edit-start="true" />
                    <DxColumn data-field="id" :visible="false" />
                    <DxColumn
                      data-field="menuNm"
                      caption="메뉴명"
                      width="220"
                      :allow-search="true"
                      :allow-sorting="false"
                      :allow-editing="false"
                      :hiding-priority="8"
                    />
                    <DxColumn
                      data-field="grpAuthNm"
                      caption="권한그룹명"
                      width="120"
                      alignment="center"
                      :allow-search="false"
                      :allow-editing="false"
                      :allow-sorting="true"
                      :hiding-priority="7"
                    />
                    <DxColumn
                      data-field="progNm"
                      caption="프로그램명"
                      width="265"
                      :allow-editing="false"
                      :allow-sorting="false"
                      :hiding-priority="6"
                    />
                    <DxColumn
                      data-field="svcGubn"
                      data-type="string"
                      caption="웹/모바일"
                      width="75"
                      alignment="center"
                      :allow-sorting="false"
                      :allow-editing="false"
                      :hiding-priority="5"
                    >
                      <DxLookup :data-source="svcGubnDataSource" display-expr="minorNm" value-expr="minorCd" />
                    </DxColumn>
                    <DxColumn
                      data-field="auth"
                      data-type="boolean"
                      caption="권한"
                      width="70"
                      :allow-sorting="false"
                      header-cell-template="title-header"
                      edit-cell-template="checkBoxEditor"
                      :hiding-priority="4"
                    />
                    <DxColumn
                      data-field="sort"
                      caption="순서"
                      width="75"
                      :allow-sorting="false"
                      header-cell-template="title-header"
                      :visible="false"
                    />
                    <DxColumn
                      data-field="schAh"
                      data-type="boolean"
                      caption="조회"
                      width="70"
                      :allow-sorting="false"
                      header-cell-template="title-header"
                      edit-cell-template="checkBoxEditor"
                      :hiding-priority="3"
                    />
                    <DxColumn
                      data-field="savAh"
                      data-type="boolean"
                      caption="저장"
                      width="70"
                      :allow-sorting="false"
                      header-cell-template="title-header"
                      edit-cell-template="checkBoxEditor"
                      :hiding-priority="2"
                    />
                    <DxColumn
                      data-field="delAh"
                      data-type="boolean"
                      caption="삭제"
                      width="70"
                      :allow-sorting="false"
                      header-cell-template="title-header"
                      edit-cell-template="checkBoxEditor"
                      :hiding-priority="1"
                    />

                    <DxColumn
                      data-field="exlAh"
                      data-type="boolean"
                      caption="츨력"
                      width="70"
                      :allow-sorting="false"
                      header-cell-template="title-header"
                      edit-cell-template="checkBoxEditor"
                      :hiding-priority="0"
                    />
                    <!-- 20220630 LYJ 현재 즐겨찾기 기능이 없으므로 노출시켜 렌더링 이슈에서 벗어나도록 우선은 막음 -->
                    <!-- <DxColumn
                      data-field="favoriteYn"
                      data-type="boolean"
                      caption="즐겨찾기"
                      width="80"
                      :allow-sorting="false"
                      header-cell-template="title-header"
                      edit-cell-template="checkBoxEditor"
                    /> -->

                    <!-- checkbox -->
                    <template #checkBoxEditor="{ data: cellInfo  }">
                      <DxCheckBox :value="cellInfo.value == 'Y' ? true : false" :on-value-changed="value => onCheckValueChanged(value, cellInfo)" />
                    </template>

                    <template #title-header="{ data }">
                      <div>
                        <!-- <p style="font-size:16px"></p> -->
                        {{ data.column.caption }}
                        <DxCheckBox width="22" :on-value-changed="value => onCheckHeaderValueChanged(value.value, data.column.name)" />
                      </div>
                    </template>
                  </DxTreeList>
                </v-col>
              </v-col>
            </v-layout>
          </template>
        </i-card-vertical>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import iPageTitle from '@/components/common/iPageTitle.vue'
import iCardVertical from '@/components/common/iCardVertical.vue'
import iCardTop from '@/components/common/iCardTop.vue'

import { DxTreeList, DxSelection, DxColumn, DxRowDragging, DxEditing, DxLookup } from 'devextreme-vue/tree-list'
import DxCheckBox from 'devextreme-vue/check-box'

import { getMenuOfgroupManage, saveMenuOfgroupManage } from '@/api/setting/menuOfgroupManage'
import { getGrpAuth, getCommonCode } from '@/api/common/commonApi'

import notify from 'devextreme/ui/notify'
import Baseview from '@/views/base/baseview.vue' //20220414 LYJ base page 추가

export default {
  extends: Baseview, //20220414 LYJ base page 추가
  name: 'menuOfgroupManage',
  components: {
    'i-page-title': iPageTitle,
    'i-card-top': iCardTop,
    iCardVertical,
    DxLookup,
    DxTreeList,
    DxSelection,
    DxColumn,
    DxRowDragging,
    DxEditing,
    DxCheckBox
  },
  data() {
    return {
      drawerLayout: false,
      dxTreeListRef: 'menuOfgroupManageTreeList',
      menus: [],
      selectList: [],
      selectedGrpAuth: '',
      buttonUseList: [
        'btnSearch', //조회
        // 'btnAdd',     //추가
        'btnSave' //저장
        // 'btnDelete'   //삭제
      ],
      // 웹/모바일 dataSource
      svcGubnDataSource: [],

      authDataSource: [
        { minorCd: '', minorNm: '전체' },
        { minorCd: 'Y', minorNm: '권한있음' },
        { minorCd: 'N', minorNm: '권한없음' }
      ],
      // vuetify의 radio value는 ""을 넣어도 0으로 값이 맞춰짐
      selectedAuth: 0,
      selectedSvcGubn: 'W'
    }
  },
  computed: {
    treeList: function() {
      return this.$refs[this.dxTreeListRef].instance
    }
  },
  beforeMount() {
    Promise.all([
      getGrpAuth(), // 권한 그룹 들고오기
      getCommonCode('C0004') // majorCd : "C0004" 프로그램 Type
    ]).then(res => {
      // 권한 그룹 들고오기
      this.selectList = []
      this.selectList = res[0].list
      //this.selectList.unshift({ grpAuthCd: '', grpAuthNm: '전체' })

      // majorCd : "C0004" 프로그램 Type
      this.svcGubnDataSource = []
      this.svcGubnDataSource = res[1].list
    })
  },
  mounted() {
    // 켜질때 조회
    this.btnSearch()
  },
  methods: {
    ///////////////////////////////////////
    /*       Toolbar Button Event        */
    ///////////////////////////////////////
    changeInput(value) {
      this.treeList.searchByText(value)
    },
    btnSearch() {
      this.treeInit()
      this.openLoading('searching')

      let params = {
        grpAuthCd: this.selectedGrpAuth,
        auth: this.selectedAuth.toString().replace(0, ''), // vuetify의 라디오 value는 "" 을 넣으면 0으로 나와서 "" 으로 바꿔줌
        svcGubn: this.selectedSvcGubn.toString().replace(0, '')
      }
      getMenuOfgroupManage(params, true)
        .then(res => {
          this.menus = []
          this.menus = res.list

          // DxtreeList 버그로 인하여 전체확장을 껏다가 킴
          this.treeList.option('autoExpandAll', false)
          this.treeList.option('autoExpandAll', true)
          // 포커스 첫번째로
          this.treeList.option('focusedRowIndex', -1)
          this.treeList.option('focusedRowIndex', 0)
        })
        .finally(() => {
          this.endLoading()
        })
    },
    async btnSave() {
      let selectedRows = this.treeList.getSelectedRowsData()
      if (selectedRows.length === 0) {
        // this.$vToastify.warning({ body: this.$t('selectionData') })
        this.vToastify(this.$t('selectionData'), 'warn')
        return
      }

      this.vToastifyPrompt(
        this.$t('doSaveData'),
        'info',
        current => {
          this.treeList.saveEditData()

          // let selectedRows = this.treeList.getSelectedRowsData()
          let selectedprogramRows = selectedRows
          this.openLoading()

          saveMenuOfgroupManage(selectedprogramRows, true)
            .then(res => {
              let params = {
                grpAuthCd: this.selectedGrpAuth,
                svcGubn: this.selectedSvcGubn.toString().replace(0, ''),
                auth: this.selectedAuth.toString().replace(0, '') // vuetify의 라디오 value는 "" 을 넣으면 0으로 나와서 "" 으로 바꿔줌
              }
              getMenuOfgroupManage(params)
                .then(res => {
                  this.treeInit()
                  this.menus = []
                  this.menus = res.list

                  // DxtreeList 버그로 인하여 전체확장을 껏다가 킴
                  this.treeList.option('autoExpandAll', false)
                  this.treeList.option('autoExpandAll', true)

                  // 포커스 첫번째로
                  this.treeList.option('focusedRowIndex', -1)
                  this.treeList.option('focusedRowIndex', 0)
                })
                .catch(error => {
                  if (error.response && error.response.data) {
                    if (error.response.data.code == -2001) {
                      this.vToastify(this.$t(error.response.data.msg), 'warn')
                    }
                  }
                })
                .finally(res => {
                  this.endLoading()
                })
            })
            .finally(res => {
              this.endLoading()
            })
        },
        null,
        true
      )
    },
    ///////////////////////////////////////
    /*            TreeList Event         */
    ///////////////////////////////////////
    onSelectionChanged(e) {
      // 최근에 선택된 열의 node 정보
      let sourceNode
      if (e.currentSelectedRowKeys.length !== 0) {
        sourceNode = this.treeList.getNodeByKey(e.currentSelectedRowKeys)
      } else {
        sourceNode = this.treeList.getNodeByKey(e.currentDeselectedRowKeys)
      }

      // 열 삭제시에도 해당 메소드를 타기때문에 return
      if (sourceNode == null) return
    },
    // 체크박스 값 변경될 시 타는 이벤트
    onCheckValueChanged(value, cellInfo) {
      cellInfo.setValue(cellInfo.value === 'Y' ? 'N' : 'Y')

      // 재귀적으로 트리아래 모든 데이터 변경을 위한 함수
      this.recursiveDataChange(cellInfo)

      this.treeList.selectRows(cellInfo.row.key, true)
      cellInfo.component.updateDimensions()
    },
    // 헤더의 값 변경될 시 타는 이벤트
    onCheckHeaderValueChanged(value, headerField) {
      this.menus.forEach(element => {
        element[headerField] = value ? 'Y' : 'N'
      })
      this.treeList.selectAll()
    },
    onEditingStart(e) {
      if (e.column.dataField == 'menuNm' || e.column.dataField == 'grpAuthNm' || e.column.dataField == 'svcGubn') e.cancel = true
    },
    onEditorPreparing(e) {
      if (e.parentType == 'dataRow') {
        var valueChanged = this.onCellValueChanged

        e.editorOptions.onValueChanged = args => {
          if (e.index > -1) valueChanged(args.value, e)
        }
      }
    },
    onCellValueChanged(value, cellInfo) {
      cellInfo.setValue(value)
      // this.treeList.selectRows(cellInfo.row.key, true)
    },

    treeInit() {
      this.treeList.clearSelection()
      this.treeList.cancelEditData()
    },
    ///////////////////////////////////////
    /*   0          etc Event             */
    ///////////////////////////////////////
    // 재귀적으로 트리아래 모든 데이터 변경을 위한 함수
    recursiveDataChange(cellInfo) {
      this.upperTreeDataChange(cellInfo)
      this.downTreeDataChange(cellInfo)
    },
    upperTreeDataChange(cellInfo) {
      // 조회, 저장, 삭제, 즐겨찾기가 선택이 되면 권한도 체크가 되어야함
      if (cellInfo.value === 'Y' && cellInfo.column.dataField !== 'auth') {
        let rowIndex = this.treeList.getRowIndexByKey(cellInfo.data.id)
        this.treeList.cellValue(rowIndex, 'auth', 'Y')

        this.treeList.selectRows(cellInfo.data.id, true)
      }

      // this.treeList.getNodeByKey 가 제대로 동작하지 않아 임시적으로 전체적으로 돌림
      this.menus.forEach(element => {
        if (element.parentId === cellInfo.data.id) {
          // 순서가 바뀌어서 변하였으니 저장하기 위해 선택 check
          // batch
          let rowIndex = this.treeList.getRowIndexByKey(element.id)
          this.treeList.cellValue(rowIndex, cellInfo.column.dataField, cellInfo.value)
          // cell mode 였을때
          //element[`${cellInfo.column.dataField}`] = cellInfo.value

          // 재귀적으로 함수를 타기위해 cellInfo 만들어줌
          let tempCellInfo = {
            data: {
              id: element.id
            },
            column: {
              dataField: cellInfo.column.dataField
            },
            value: cellInfo.value
          }

          this.upperTreeDataChange(tempCellInfo)
        }
      })
    },
    downTreeDataChange(cellInfo) {
      //부모 객체 가져오기
      let parent = this.menus.find(element => element.id === cellInfo.data.parentId)

      //최상위면 return
      if (parent == null) return

      switch (cellInfo.value === 'Y') {
        case cellInfo.column.dataField == 'auth':
          parent.auth = 'Y'
          break
        case cellInfo.column.dataField == 'schAh':
          parent.schAh = 'Y'
          break
        case cellInfo.column.dataField == 'savAh':
          parent.savAh = 'Y'
          break
        case cellInfo.column.dataField == 'delAh':
          parent.delAh = 'Y'
          break
        case cellInfo.column.dataField == 'exlAh':
          parent.exlAh = 'Y'
          break
      }
      // 조회, 저장, 삭제, 즐겨찾기가 선택이 되면 권한도 체크가 되어야함
      if (cellInfo.value === 'Y' && cellInfo.column.dataField !== 'auth') {
        let rowIndex = this.treeList.getRowIndexByKey(cellInfo.data.id)
        this.treeList.cellValue(rowIndex, 'auth', 'Y')

        this.treeList.selectRows(cellInfo.data.id, true)
      }

      // 취소될때 같은 레벨에 체크가 되어있는지 확인하고 모두 취소가 되면 부모 취소
      if (cellInfo.value === 'N') {
        let otherChilden = this.menus.findIndex(element => element.parentId === cellInfo.data.parentId && element.auth === 'Y')
        if (otherChilden > -1) return
      }

      // batch
      let rowIndex = this.treeList.getRowIndexByKey(cellInfo.data.id)
      this.treeList.cellValue(rowIndex, cellInfo.column.dataField, cellInfo.value)
      // cell mode 였을때
      // parent[`${cellInfo.column.dataField}`] = cellInfo.value

      let tempCellInfo = {
        data: {
          id: parent.id,
          parentId: parent.parentId
        },
        column: {
          dataField: cellInfo.column.dataField
        },
        value: cellInfo.value
      }
      this.downTreeDataChange(tempCellInfo)
    }
  }
}
</script>
<style lang="scss" scoped>
